import React, { useState, useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Header from '../components/common/Header';
import Navbar from '../components/common/Navbar';
import Footer from '../components/common/Footer';
import { CartContext } from '../context/CartContext';
import { AuthContext } from '../context/AuthContext';
import { orderAPI } from '../api'; // THÊM IMPORT API

const Checkout = () => {
  const { cartItems, getCartTotal, clearCart } = useContext(CartContext);
  const { user } = useContext(AuthContext);
  const navigate = useNavigate();
  
  const [loading, setLoading] = useState(false); // THÊM LOADING STATE
  const [error, setError] = useState(''); // THÊM ERROR STATE
  
  const [formData, setFormData] = useState({
    fullName: user?.name || '',
    email: user?.email || '',
    phone: '',
    address: '',
    city: 'hcm',
    district: '',
    notes: '',
    paymentMethod: 'cod'
  });

  // Danh sách các quận TP.HCM
  const hcmDistricts = [
    { value: 'quan1', label: 'Quận 1' },
    { value: 'quan2', label: 'Quận 2' },
    { value: 'quan3', label: 'Quận 3' },
    { value: 'quan4', label: 'Quận 4' },
    { value: 'quan5', label: 'Quận 5' },
    { value: 'quan6', label: 'Quận 6' },
    { value: 'quan7', label: 'Quận 7' },
    { value: 'quan8', label: 'Quận 8' },
    { value: 'quan9', label: 'Quận 9' },
    { value: 'quan10', label: 'Quận 10' },
    { value: 'quan11', label: 'Quận 11' },
    { value: 'quan12', label: 'Quận 12' },
    { value: 'binhtan', label: 'Quận Bình Tân' },
    { value: 'binhthạnh', label: 'Quận Bình Thạnh' },
    { value: 'govap', label: 'Quận Gò Vấp' },
    { value: 'phunhuan', label: 'Quận Phú Nhuận' },
    { value: 'tanbình', label: 'Quận Tân Bình' },
    { value: 'tanphu', label: 'Quận Tân Phú' },
    { value: 'thuduc', label: 'TP. Thủ Đức' }
  ];
  
  const calculateShippingFee = () => {
    const cartTotal = getCartTotal();
    return cartTotal >= 500000 ? 0 : 30000;
  };

  const shippingFee = calculateShippingFee();
  const finalTotal = getCartTotal() + shippingFee;

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    if (name === 'city') {
      setFormData(prev => ({
        ...prev,
        district: ''
      }));
    }
  };
  
  // ========== SỬA HANDLESUBMIT ĐỂ GỌI API THẬT ==========
  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Kiểm tra đăng nhập
    if (!user) {
      alert('Vui lòng đăng nhập để đặt hàng');
      navigate('/login');
      return;
    }

    // Validate form
    if (!formData.fullName || !formData.email || !formData.phone || !formData.address || !formData.district) {
      alert('Vui lòng điền đầy đủ thông tin bắt buộc');
      return;
    }

    setLoading(true);
    setError('');

    try {
      console.log('🛒 Đang tạo đơn hàng...');
      
      // Chuẩn bị dữ liệu đơn hàng theo format backend mong đợi
      const orderData = {
        orderItems: cartItems.map(item => ({
          name: item.name,
          quantity: item.quantity,
          image: item.image || item.images?.[0] || '/uploads/default.jpg',
          price: item.discountPrice || item.price,
          product: item._id // Product ID
        })),
        shippingAddress: {
          address: `${formData.address}, ${hcmDistricts.find(d => d.value === formData.district)?.label || formData.district}`,
          city: 'TP. Hồ Chí Minh',
          phone: formData.phone,
          postalCode: ''
        },
        paymentMethod: formData.paymentMethod === 'cod' ? 'COD' : 'BANK_TRANSFER',
        totalPrice: finalTotal
      };

      console.log('📦 Order data to send:', orderData);

      // Gọi API tạo đơn hàng
      const response = await orderAPI.createOrder(orderData);
      
      console.log('✅ Order response:', response.data);

      // Kiểm tra response
      if (response.data && (response.data.success || response.data._id)) {
        const orderId = response.data.data?._id || response.data._id;
        
        console.log(`🎉 Đặt hàng thành công! Order ID: ${orderId}`);
        
        // Xóa giỏ hàng
        clearCart();
        
        // Chuyển đến trang cảm ơn với thông tin đơn hàng
        navigate('/thank-you', {
          state: {
            orderData: response.data,
            customerInfo: formData
          }
        });
      } else {
        throw new Error('Invalid response from server');
      }

    } catch (error) {
      console.error('❌ Error creating order:', error);
      
      let errorMessage = 'Có lỗi xảy ra khi đặt hàng. Vui lòng thử lại.';
      
      if (error.response) {
        // Server trả về lỗi
        const serverError = error.response.data;
        errorMessage = serverError.message || `Lỗi ${error.response.status}: ${error.response.statusText}`;
      } else if (error.request) {
        // Không nhận được response
        errorMessage = 'Không thể kết nối đến server. Vui lòng kiểm tra kết nối mạng.';
      }
      
      setError(errorMessage);
      alert(errorMessage);
    } finally {
      setLoading(false);
    }
  };
  
  if (cartItems.length === 0) {
    return (
  <div className="flex flex-col min-h-screen bg-[#fff7f9]">
    <Header />
    <Navbar />

    <main className="flex-1 p-4 max-w-6xl mx-auto my-6">

      <h1 className="text-3xl font-bold text-[#4b2c35] mb-6 text-center">
        Thanh toán đơn hàng
      </h1>

      {error && (
        <div className="bg-red-50 border border-red-300 text-red-700 px-4 py-3 rounded-lg mb-6">
          <strong>Lỗi:</strong> {error}
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {/* LEFT COLUMN: FORM */}
        <div className="md:col-span-2 bg-white shadow-md rounded-2xl p-6 border border-pink-200">
          <form onSubmit={handleSubmit}>

            <h2 className="text-xl font-bold text-[#4b2c35] mb-4">
              🌸 Thông tin giao hàng
            </h2>

            {/* Full Name + Email */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
              <div>
                <label className="block mb-1 text-[#4b2c35]">Họ tên *</label>
                <input
                  type="text"
                  name="fullName"
                  value={formData.fullName}
                  onChange={handleChange}
                  className="w-full px-4 py-2 border border-pink-300 rounded-xl focus:ring-2 focus:ring-[#e06c7f] outline-none bg-white"
                  required
                />
              </div>

              <div>
                <label className="block mb-1 text-[#4b2c35]">Email *</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  className="w-full px-4 py-2 border border-pink-300 rounded-xl focus:ring-2 focus:ring-[#e06c7f] outline-none bg-white"
                  required
                />
              </div>
            </div>

            {/* Phone */}
            <div className="mb-4">
              <label className="block mb-1 text-[#4b2c35]">Số điện thoại *</label>
              <input
                type="tel"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                className="w-full px-4 py-2 border border-pink-300 rounded-xl focus:ring-2 focus:ring-[#e06c7f] outline-none bg-white"
                required
              />
            </div>

            {/* Address */}
            <div className="mb-4">
              <label className="block mb-1 text-[#4b2c35]">Địa chỉ cụ thể *</label>
              <input
                type="text"
                name="address"
                value={formData.address}
                onChange={handleChange}
                className="w-full px-4 py-2 border border-pink-300 rounded-xl focus:ring-2 focus:ring-[#e06c7f] outline-none bg-white"
                required
              />
            </div>

            {/* City + District */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
              <div>
                <label className="block mb-1 text-[#4b2c35]">Thành phố *</label>
                <select
                  disabled
                  className="w-full px-4 py-2 border border-pink-300 rounded-xl bg-gray-100"
                >
                  <option>TP. Hồ Chí Minh</option>
                </select>
              </div>

              <div>
                <label className="block mb-1 text-[#4b2c35]">Quận/Huyện *</label>
                <select
                  name="district"
                  value={formData.district}
                  onChange={handleChange}
                  className="w-full px-4 py-2 border border-pink-300 rounded-xl focus:ring-2 focus:ring-[#e06c7f] bg-white"
                  required
                >
                  <option value="">Chọn Quận/Huyện</option>
                  {hcmDistricts.map((d) => (
                    <option key={d.value} value={d.value}>{d.label}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Notes */}
            <div>
              <label className="block mb-1 text-[#4b2c35]">Ghi chú đơn hàng</label>
              <textarea
                name="notes"
                value={formData.notes}
                onChange={handleChange}
                rows="3"
                className="w-full px-4 py-2 border border-pink-300 rounded-xl focus:ring-2 focus:ring-[#e06c7f] outline-none bg-white"
              ></textarea>
            </div>

            {/* PAYMENT METHOD */}
            <h2 className="text-xl font-bold text-[#4b2c35] mt-8 mb-3">
              💳 Phương thức thanh toán
            </h2>

            <div className="space-y-3">
              {/* COD */}
              <label className="flex items-start p-3 border border-pink-200 rounded-xl cursor-pointer hover:bg-pink-50">
                <input
                  type="radio"
                  name="paymentMethod"
                  value="cod"
                  checked={formData.paymentMethod === "cod"}
                  onChange={handleChange}
                  className="mt-1 mr-3 accent-[#e06c7f]"
                />
                <div>
                  <span className="font-medium text-[#4b2c35]">Thanh toán khi nhận hàng (COD)</span>
                </div>
              </label>

              {/* Bank transfer */}
              <label className="flex items-start p-3 border border-pink-200 rounded-xl cursor-pointer hover:bg-pink-50">
                <input
                  type="radio"
                  name="paymentMethod"
                  value="bank"
                  checked={formData.paymentMethod === "bank"}
                  onChange={handleChange}
                  className="mt-1 mr-3 accent-[#e06c7f]"
                />
                <div>
                  <span className="font-medium text-[#4b2c35]">Chuyển khoản ngân hàng</span>
                </div>
              </label>
            </div>

            {/* SUBMIT BUTTON */}
            <button
              type="submit"
              disabled={loading}
              className={`w-full mt-6 py-3 rounded-xl font-bold text-lg shadow-md transition 
                ${loading ? "bg-gray-300 text-gray-600" : "bg-[#e06c7f] text-white hover:bg-[#cc5f72]"}`}
            >
              {loading ? "Đang xử lý..." : `🛒 Đặt hàng (${finalTotal.toLocaleString("vi-VN")}₫)`}
            </button>

          </form>
        </div>

        {/* RIGHT COLUMN: ORDER SUMMARY */}
        <div className="bg-white shadow-md rounded-2xl p-6 border border-pink-200">

          <h2 className="text-xl font-bold text-[#4b2c35] mb-4">Đơn hàng của bạn</h2>

          <div className="space-y-3 mb-4">
            {cartItems.map((item) => (
              <div key={item._id} className="flex justify-between border-b border-pink-100 pb-2 pt-2">
                <span className="text-[#4b2c35]">
                  {item.name} × {item.quantity}
                </span>
                <span className="text-[#4b2c35] font-medium">
                  {((item.discountPrice || item.price) * item.quantity).toLocaleString("vi-VN")}₫
                </span>
              </div>
            ))}
          </div>

          <div className="flex justify-between mb-2">
            <span className="text-[#4b2c35]">Tạm tính:</span>
            <span>{getCartTotal().toLocaleString("vi-VN")}₫</span>
          </div>

          <div className="flex justify-between mb-2">
            <span className="text-[#4b2c35]">Phí giao hàng:</span>
            <span className={shippingFee === 0 ? "text-green-600" : "text-[#4b2c35]"}>
              {shippingFee === 0 ? "Miễn phí" : "30.000₫"}
            </span>
          </div>

          <div className="flex justify-between font-bold text-lg mt-4 pt-3 border-t border-pink-200">
            <span className="text-[#4b2c35]">Tổng cộng:</span>
            <span className="text-[#e06c7f]">{finalTotal.toLocaleString("vi-VN")}₫</span>
          </div>

        </div>
      </div>
    </main>

    <Footer />
  </div>
);
  }
};

export default Checkout;
